2,0.04177994,-0.05059123,0.03050176,-0.02334297,-0.05958816,0.05312869,0.05094057,0.02627844,0.01150490,0.10993176,0.00772241,-0.00150722,0.01171910,0.01168535,0.01446978,-0.00013961,-0.01471356,-0.02168433,0.01229982,-0.02959818,0.01137888,0.03580671,-0.08285360,-0.03121520,-0.02071824,-0.06309389,-0.00705395,-0.05130048,-0.03643969,0.01099823,-0.05841646,0.01696654,0.04133271,-0.02838321,-0.04207844,-0.07125352,0.02883572,0.03581810,-0.04432226,0.00633850,-0.00798512,0.03237595]',E'Rendering lists {/*rendering-lists*/}\n\n<Sandpack>\n\n```js\nconst products = [\n  { title: ''Cabbage'', isFruit: false, id: 1 },\n  { title: ''Garlic'', isFruit: false, id: 2 },\n  { title: ''Apple'', isFruit: true, id: 3 },\n];\n\nexport default function ShoppingList() {\n  const listItems = products.map(product =>\n    <li\n      key={product.id}\n      style={{\n        color: product.isFruit ? ''magenta'' : ''darkgreen''\n      }}\n    >\n      {product.title}\n    </li>\n  );\n\n  return (\n    <ul>{listItems}</ul>\n  );\n}\n```\n\n</Sandpack>','{"source": "react", "version": "19", "language": "typescript", "title": "Index", "section_title": "index", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/index.md", "topics": "react,hooks,index", "categories": "web,typescript,frontend,spa"}');
