391427,0.01833864,0.03486271,-0.02910257,-0.03119384,-0.01677825,0.08693829,0.01121898,-0.01186953,-0.02861381,0.04659519,0.00469576,-0.03628577,-0.08914294,0.00680670,0.05670360,-0.00059069,-0.01892703,-0.02790877,0.05054590,0.00751426,-0.04214219,0.02318220,-0.03775862,-0.00245930,-0.06490518,-0.01756436,0.02446112,0.00259119,-0.00904187,0.01328489,-0.01031221,0.01463391,0.04046940,0.04994760,0.02031346,-0.00664752,0.04362188,0.07674059,-0.03742019,0.03575398,0.05430850,0.02588535]',E'Passing event handlers as props {/*passing-event-handlers-as-props*/}\n\nfunction PlayButton({ movieName }) {\n  function handlePlayClick() {\n    alert(`Playing ${movieName}!`);\n  }\n\n  return (\n    <Button onClick={handlePlayClick}>\n      Play "{movieName}"\n    </Button>\n  );\n}\n\nfunction UploadButton() {\n  return (\n    <Button onClick={() => alert(''Uploading!'')}>\n      Upload Image\n    </Button>\n  );\n}\n\nexport default function Toolbar() {\n  return (\n    <div>\n      <PlayButton movieName="Kiki''s Delivery Service" />\n      <UploadButton />\n    </div>\n  );\n}\n```','{"source": "react", "version": "19", "language": "typescript", "title": "Responding To Events", "section_title": "responding-to-events", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/responding-to-events.md", "topics": "react,hooks,responding,to,events", "categories": "web,typescript,frontend,spa"}');
