8,0.01923660,0.04356368,-0.00034522,-0.02665056,0.02893145,0.07619359,0.00496195,-0.00787002,-0.03006346,0.02724321,-0.01182048,-0.01136257,-0.08191567,0.03869080,0.01438142,0.00872597,0.00340255,-0.02061652,0.03637939,0.01198139,-0.01979715,0.03499702,-0.07866723,0.01250708,-0.02855676,-0.02861906,0.01659769,-0.02558877,-0.02596491,-0.00424913,-0.02337577,0.02125045,0.02581048,0.03788438,0.00599008,-0.01110075,0.01760608,0.02014507,-0.03981948,0.05390836,0.02189763,0.01590636]',E'Naming event handler props {/*naming-event-handler-props*/}\n\n<Sandpack>\n\n```js\nfunction Button({ onSmash, children }) {\n  return (\n    <button onClick={onSmash}>\n      {children}\n    </button>\n  );\n}\n\nexport default function App() {\n  return (\n    <div>\n      <Button onSmash={() => alert(''Playing!'')}>\n        Play Movie\n      </Button>\n      <Button onSmash={() => alert(''Uploading!'')}>\n        Upload Image\n      </Button>\n    </div>\n  );\n}\n```\n\n```css\nbutton { margin-right: 10px; }\n```\n\n</Sandpack>','{"source": "react", "version": "19", "language": "typescript", "title": "Responding To Events", "section_title": "responding-to-events", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/responding-to-events.md", "topics": "react,hooks,responding,to,events", "categories": "web,typescript,frontend,spa"}');
