.02390023,-0.02906325,-0.07130541,-0.05618851,0.02832774,-0.02860185,-0.10633489,0.02048230,0.01038167,-0.10914726,-0.03289090,-0.01619442,0.01256404,0.01982006,-0.06783402,0.01159700,0.00661556,-0.01712308,-0.04731826,-0.03472044,-0.05321444,0.03632085,0.02923785,-0.02286503,-0.05773858,-0.00486106,0.01017517,-0.02985165,0.03237176,-0.03893244,-0.04503433,0.04997569,-0.01831993,0.03925537,0.00013304,-0.00434816,-0.00488488,0.00771488,0.08409892,0.00852507,-0.00875809,0.04448030,-0.01350934,-0.10527924,0.03637259,0.01740645,-0.03319243,-0.01623799,-0.01317653,-0.04068206,0.05233747,-0.03869089,0.06410839,-0.02869375,0.01388072,0.01847906,-0.31118447,-0.01465698,0.04960662,0.00770191,-0.01066082,-0.03618686,0.02326138,-0.00585980,-0.03161646,-0.00539091,0.08455932,0.08315808,-0.01559262,-0.08050815,-0.01517494,0.01546270,0.01498025,-0.01796382,-0.04158758,0.05229081,-0.01135959,-0.01804612,-0.00791725,-0.08176853,0.02055792,-0.00135206,0.10041198,0.03707916,0.04918319,-0.01617013,0.04619370,-0.01731348,-0.02214620,-0.00472388,-0.04743788,0.00233379,-0.00763958,-0.01412715,0.00713326,-0.01218488,-0.02442160,0.01363108,-0.00413209,-0.00964447,0.02989296,-0.01972340,-0.03925250,-0.04618805,0.01959792,-0.04619550,0.05626272,-0.04315661,0.03357621,0.03229301,0.01841628,0.02251623,0.02760431,0.00876263,-0.07238335,-0.00997381,-0.01409263,0.04334160,-0.01752854,-0.01883163,0.06119987,0.03390261,0.05297464,-0.03813049,0.04732956,0.02800365,-0.01123165,0.14126112,0.02844633,0.02435401,0.03055819,0.01000509,0.00457317,0.00253311,-0.03599591,0.02259702,0.01117021,0.00794686,0.02758078,0.06103525,-0.04805862,0.05520064,0.03491178,-0.02079549,-0.01510865,-0.06861142,-0.00016753,0.05223936,-0.03935267,0.01302521,-0.02363311,-0.00919836,-0.23065181,-0.00237187,0.08443945,0.03091350,0.02265037,0.03495142,0.05876463,-0.03037319,-0.00452907,-0.00314011,-0.05091840,0.02794013,0.02393523,0.01965160,0.02988129,0.08931813,0.02182200,0.02506721,-0.02661484,-0.02975203,0.12757060,0.04758280,0.18602729,0.05947620,0.05327310,-0.02273213,-0.06065671,0.00039033,0.00266039,-0.00913706,-0.07705246,-0.03873786,0.03732667,-0.00002893,0.00634413,-0.02485326,0.01589802,0.07331688,0.00662883,-0.02469775,0.00894289,0.04283477,0.02448579,-0.07123650,0.05003472,-0.07695227,-0.01697340,-0.01980356,-0.02156183,0.06830111,-0.02591273,-0.07556033,0.02641608,-0.03832044,-0.00005185,0.08457675,-0.02810196,0.00506198,0.01389451,0.04449300,0.08713758,0.04369827,0.04960732,-0.00004755,0.06184641]',E'Capture phase events {/*capture-phase-events*/}\n\nIn rare cases, you might need to catch all events on child elements, *even if they stopped propagation*. For example, maybe you want to log every click to analytics, regardless of the propagation logic. You can do this by adding `Capture` at the end of the event name:\n\n```js\n<div onClickCapture={() => { /* this runs first */ }}>\n  <button onClick={e => e.stopPropagation()} />\n  <button onClick={e => e.stopPropagation()} />\n</div>\n```\n\nEach event propagates in three phases:\n\n1. It travels down, calling all `onClickCapture` handlers.\n2. It runs the clicked element''s `onClick` handler.\n3. It travels upwards, calling all `onClick` handlers.\n\nCapture events are useful for code like routers or analytics, but you probably won''t use them in app code.\n\n</DeepDive>','{"source": "react", "version": "19", "language": "typescript", "title": "Responding To Events", "section_title": "responding-to-events", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/responding-to-events.md", "topics": "react,hooks,responding,to,events", "categories": "web,typescript,frontend,spa"}');
