695705,0.02224151,0.02638229,-0.12168008,-0.02636376,0.03154305,-0.02698883,-0.05490106,0.01609995,0.04848429,-0.03612552,-0.03382957,0.02050356,0.04820858,0.09041461,-0.07970230,0.01448882,0.03937005,-0.03387602,0.01367642,-0.01394338,-0.01972270,-0.00504248,-0.01863093,-0.03189802,-0.02445075,-0.02366559,-0.01570196,0.00266658,0.04746615,-0.02387143,-0.06582738,0.04164221,0.03581613,0.02376885,0.04704055,-0.01076629,0.00847248,-0.06574709,0.06083254,0.04466726,-0.02714869,0.05869932,-0.01912221,-0.13679938,0.01387689,0.02742472,0.00477283,-0.03747389,-0.03157599,-0.04040726,0.08161448,-0.02584063,0.03673203,-0.07915951,-0.01071150,0.02327278,-0.28869900,-0.06338451,0.05908499,-0.00757391,0.01109795,-0.05001591,0.04246469,-0.01104269,-0.03679449,0.01975273,0.08513276,0.02143722,-0.03361217,-0.06018436,0.01514560,0.00898134,0.03649042,-0.04950057,0.00225587,-0.00986656,-0.02916400,-0.00324405,0.03550854,-0.12894267,-0.03980469,0.00047883,0.07837607,-0.00742928,0.07999918,-0.00852130,0.04387139,0.00944573,-0.00644330,0.03491449,-0.02741824,0.00477666,0.02360326,-0.02490454,0.02603724,-0.00220132,-0.01783516,-0.02108476,-0.02179334,-0.03361825,0.01008943,-0.03734161,0.01151951,-0.04865894,-0.00429123,-0.00823758,0.02808041,-0.04919025,0.04026714,0.01005561,-0.00046868,0.01083586,0.05350121,-0.00368085,-0.05638580,-0.00553559,-0.01681291,0.05724523,-0.00937548,-0.04783048,0.01245318,-0.00485287,0.03695974,-0.00024827,0.02474387,0.03873304,-0.02309964,0.14544569,-0.01240311,0.01018300,-0.00859872,0.06308793,-0.00870655,0.02750933,-0.05710403,0.03746336,-0.00693775,0.05457264,0.02426710,0.02954365,-0.00510934,-0.03644093,-0.00796120,-0.00194300,-0.02117254,-0.04042927,-0.04746494,0.04137266,-0.00283993,0.00124811,-0.02498787,-0.01968145,-0.25351545,-0.01183814,0.12345318,0.01420753,-0.04018883,0.02119522,0.05299452,-0.04398236,-0.03534181,0.00243459,-0.02426467,0.02236227,0.03065983,0.07442638,0.08661439,0.06081721,0.01930095,0.01673157,-0.02018986,-0.00078860,0.09321072,0.00938003,0.22631647,0.05767268,0.06983197,0.01958454,-0.05021575,-0.02479205,0.08320681,-0.00421976,-0.02936527,-0.00036415,0.05792676,-0.02690260,0.02595324,-0.11063140,0.02054026,0.05820310,-0.00706544,-0.08004491,-0.02850530,0.02448824,0.00231433,-0.01779059,0.07656492,-0.04191826,-0.03307077,-0.06235667,0.02718588,0.02168861,-0.01106956,0.01003230,0.01590496,-0.02426941,0.01142438,0.08593068,-0.00899189,-0.01607338,-0.04513668,0.00600877,0.09133500,-0.02773296,0.04587521,0.05303366,0.07560302]',E'Passing handlers as alternative to propagation {/*passing-handlers-as-alternative-to-propagation*/}\n\nNotice how this click handler runs a line of code _and then_ calls the `onClick` prop passed by the parent:\n\n```js {4,5}\nfunction Button({ onClick, children }) {\n  return (\n    <button onClick={e => {\n      e.stopPropagation();\n      onClick();\n    }}>\n      {children}\n    </button>\n  );\n}\n```\n\nYou could add more code to this handler before calling the parent `onClick` event handler, too. This pattern provides an *alternative* to propagation. It lets the child component handle the event, while also letting the parent component specify some additional behavior. Unlike propagation, it''s not automatic. But the benefit of this pattern is that you can clearly follow the whole chain of code that executes as a result of some event.\n\nIf you rely on propagation and it''s difficult to trace which handlers execute and why, try this approach instead.','{"source": "react", "version": "19", "language": "typescript", "title": "Responding To Events", "section_title": "responding-to-events", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/responding-to-events.md", "topics": "react,hooks,responding,to,events", "categories": "web,typescript,frontend,spa"}');
