2,-0.01870934,0.02427256,0.00488643,0.02379182,0.04047712,-0.02614141,-0.06304447,-0.01910513,0.05594794,-0.02354575,-0.02758976,-0.05751833,-0.02431419,0.03744619,-0.01025147,-0.00102821,-0.04797906,-0.01119151,-0.00475529,0.02717897,0.06876242,-0.05262845,0.01998817,-0.04891947,-0.07010745,0.01459077,-0.05342560,-0.02071727,0.06103895,-0.04364647,-0.03036760,-0.00189417,-0.00571360,-0.01903509,-0.05527446,-0.00891853,0.03282697,0.01822429,0.07807665,0.00068971,0.04280090]',E'Why was the ref omitted from the dependency array? {/*why-was-the-ref-omitted-from-the-dependency-array*/}\n\n```js {9}\nfunction VideoPlayer({ src, isPlaying }) {\n  const ref = useRef(null);\n  useEffect(() => {\n    if (isPlaying) {\n      ref.current.play();\n    } else {\n      ref.current.pause();\n    }\n  }, [isPlaying, ref]);\n```\n\nThe [`set` functions](/reference/react/useState#setstate) returned by `useState` also have stable identity, so you will often see them omitted from the dependencies too. If the linter lets you omit a dependency without errors, it is safe to do.','{"source": "react", "version": "19", "language": "typescript", "title": "Synchronizing With Effects", "section_title": "synchronizing-with-effects", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/synchronizing-with-effects.md", "topics": "react,hooks,synchronizing,with,effects", "categories": "web,typescript,frontend,spa"}');
