.20133935,0.04360787,0.01281654,0.02447988,0.01530131,0.03428176,0.09506164,0.04391123,-0.11088227,-0.01548981,0.00309775,0.02189197,0.01584262,-0.01140472,-0.00799384,0.03308947,0.00480895,-0.03286222,-0.02262976,0.03063136,0.03399634,-0.02419989,0.07901913,-0.07522769,-0.08326906,-0.01385708,0.00596687,0.01546933,-0.04312326,-0.03068095,0.02443537,-0.05266988,-0.03274895,0.03630337,-0.05488855,0.00105653,0.02211577,-0.02972598,0.02607667,-0.05286596,0.08629802,-0.04086110,0.01926682]',E'Fix an interval that fires twice {/*fix-an-interval-that-fires-twice*/}\n\n<Hint>\n\nKeep in mind that `setInterval` returns an interval ID, which you can pass to [`clearInterval`](https://developer.mozilla.org/en-US/docs/Web/API/clearInterval) to stop the interval.\n\n</Hint>\n\n<Sandpack>\n\n```js src/Counter.js active\nimport { useState, useEffect } from ''react'';\n\nexport default function Counter() {\n  const [count, setCount] = useState(0);\n\n  useEffect(() => {\n    function onTick() {\n      setCount(c => c + 1);\n    }\n\n    setInterval(onTick, 1000);\n  }, []);','{"source": "react", "version": "19", "language": "typescript", "title": "Synchronizing With Effects", "section_title": "synchronizing-with-effects", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/synchronizing-with-effects.md", "topics": "react,hooks,synchronizing,with,effects", "categories": "web,typescript,frontend,spa"}');
