53,0.19907981,0.03502733,0.02506376,0.03963200,0.00320968,0.02019268,0.10176154,0.05063549,-0.10826789,-0.00893156,0.00800051,0.01954187,0.01690936,-0.01179815,0.00173340,0.04900130,-0.00721097,-0.02640579,-0.03360808,0.02601973,0.03306976,-0.00045358,0.07400046,-0.07282113,-0.07268095,-0.02668000,-0.00870852,0.01406146,-0.03751122,-0.03936502,0.03670247,-0.05290636,-0.02837755,0.03923375,-0.06236120,0.00605654,0.00649735,-0.02381424,0.02402578,-0.05117926,0.10291832,-0.02946546,0.00624698]',E'Fix an interval that fires twice {/*fix-an-interval-that-fires-twice*/}\n\n<Sandpack>\n\n```js src/Counter.js active\nimport { useState, useEffect } from ''react'';\n\nexport default function Counter() {\n  const [count, setCount] = useState(0);\n\n  useEffect(() => {\n    function onTick() {\n      setCount(c => c + 1);\n    }\n\n    const intervalId = setInterval(onTick, 1000);\n    return () => clearInterval(intervalId);\n  }, []);\n\n  return <h1>{count}</h1>;\n}\n```\n\n```js src/App.js hidden\nimport { useState } from ''react'';\nimport Counter from ''./Counter.js'';','{"source": "react", "version": "19", "language": "typescript", "title": "Synchronizing With Effects", "section_title": "synchronizing-with-effects", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/synchronizing-with-effects.md", "topics": "react,hooks,synchronizing,with,effects", "categories": "web,typescript,frontend,spa"}');
