360,0.00364673,0.04306236,0.05550779,-0.00303236,-0.00608396,0.08482388,0.01863071,-0.04266616,-0.00202830,0.07398345,0.01986664,0.00344648,-0.03656792,0.01740112,0.05465253,-0.03257244,0.00703598,-0.02160052,-0.00021806,0.04105926,0.01451917,0.08312830,-0.07573844,-0.03163954,-0.07345829,-0.04835649,-0.01161118,-0.05018301,-0.02976064,0.04122947,-0.04294937,-0.02707015,0.02156497,0.00305680,-0.01602117,-0.01724561,0.01071372,0.04457442,-0.00376268,0.09551600,0.01418745,0.03899222]',E'Example: building a stopwatch {/*example-building-a-stopwatch*/}\n\n<Sandpack>\n\n```js\nimport { useState, useRef } from ''react'';\n\nexport default function Stopwatch() {\n  const [startTime, setStartTime] = useState(null);\n  const [now, setNow] = useState(null);\n  const intervalRef = useRef(null);\n\n  function handleStart() {\n    setStartTime(Date.now());\n    setNow(Date.now());\n\n    clearInterval(intervalRef.current);\n    intervalRef.current = setInterval(() => {\n      setNow(Date.now());\n    }, 10);\n  }','{"source": "react", "version": "19", "language": "typescript", "title": "Referencing Values With Refs", "section_title": "referencing-values-with-refs", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/referencing-values-with-refs.md", "topics": "react,hooks,referencing,values,with,refs", "categories": "web,typescript,frontend,spa"}');
