8930,0.02595033,0.01547139,0.01575119,0.00705666,-0.00307733,0.10582190,0.01749709,-0.04077814,0.02989905,0.02655045,-0.01559855,0.01244922,-0.11064250,-0.06024728,0.03216567,-0.00237271,-0.00933838,-0.03610711,0.04545016,0.06788031,-0.02342183,0.02902701,-0.00003230,-0.04684785,-0.04045187,-0.03366470,0.01336502,-0.01554098,-0.02355068,0.04356054,-0.02697959,-0.01620560,0.03701678,-0.01280561,0.04550994,-0.00499030,0.00125944,0.01988250,-0.02082386,0.10514069,0.02774013,0.02793616]',E'Fix a broken chat input {/*fix-a-broken-chat-input*/}\n\n```js\nimport { useState, useRef } from ''react'';\n\nexport default function Chat() {\n  const [text, setText] = useState('''');\n  const [isSending, setIsSending] = useState(false);\n  const timeoutRef = useRef(null);\n\n  function handleSend() {\n    setIsSending(true);\n    timeoutRef.current = setTimeout(() => {\n      alert(''Sent!'');\n      setIsSending(false);\n    }, 3000);\n  }\n\n  function handleUndo() {\n    setIsSending(false);\n    clearTimeout(timeoutRef.current);\n  }','{"source": "react", "version": "19", "language": "typescript", "title": "Referencing Values With Refs", "section_title": "referencing-values-with-refs", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/referencing-values-with-refs.md", "topics": "react,hooks,referencing,values,with,refs", "categories": "web,typescript,frontend,spa"}');
