,0.05547734,0.00727314,0.04166844,-0.01980760,0.00312073,0.09765062,0.02600945,-0.05995333,-0.03617871,0.03127709,0.00681763,0.04347939,-0.05347184,-0.02046298,-0.00065690,0.03625149,-0.01785499,0.00179821,0.04313833,0.02997900,0.03379650,0.08694735,-0.04933031,-0.02362828,-0.01163061,-0.07160268,-0.01087133,-0.01799198,-0.01502757,0.01889432,-0.07812859,0.00168978,0.02952507,-0.04743910,-0.01472017,-0.02530172,-0.04471301,0.03729735,-0.00632839,0.06573799,-0.00431027,0.04496101]',E'Fix a component failing to re-render {/*fix-a-component-failing-to-re-render*/}\n\n</Sandpack>\n\n<Solution>\n\nIn this example, the current value of a ref is used to calculate the rendering output: `{isOnRef.current ? ''On'' : ''Off''}`. This is a sign that this information should not be in a ref, and should have instead been put in state. To fix it, remove the ref and use state instead:\n\n<Sandpack>\n\n```js\nimport { useState } from ''react'';\n\nexport default function Toggle() {\n  const [isOn, setIsOn] = useState(false);','{"source": "react", "version": "19", "language": "typescript", "title": "Referencing Values With Refs", "section_title": "referencing-values-with-refs", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/referencing-values-with-refs.md", "topics": "react,hooks,referencing,values,with,refs", "categories": "web,typescript,frontend,spa"}');
