,0.15993012,0.06043298,0.00824403,0.06226189,0.00363242,0.05813325,0.08095428,-0.04439063,-0.06141031,0.01513957,0.05788560,-0.01700720,-0.04510317,-0.08303941,-0.07577161,-0.03473645,0.03834254,0.01132310,-0.02524087,-0.02071267,0.02131844,-0.02338256,0.10421589,-0.06746988,-0.04840781,-0.04543309,-0.03352408,-0.01644953,-0.02374969,-0.06538507,-0.02356104,-0.00715463,0.00264766,0.06021224,0.02917212,-0.01612338,0.02102946,-0.00425539,0.01583264,-0.01799684,0.01458694,-0.04143224,0.02794130]',E'Fix debouncing {/*fix-debouncing*/}\n\n<Hint>\n\nThe last timeout ID variable is shared between all `DebouncedButton` components. This is why clicking one button resets another button''s timeout. Can you store a separate timeout ID for each button?\n\n</Hint>\n\n<Sandpack>\n\n```js\nlet timeoutID;\n\nfunction DebouncedButton({ onClick, children }) {\n  return (\n    <button onClick={() => {\n      clearTimeout(timeoutID);\n      timeoutID = setTimeout(() => {\n        onClick();\n      }, 1000);\n    }}>\n      {children}\n    </button>\n  );\n}','{"source": "react", "version": "19", "language": "typescript", "title": "Referencing Values With Refs", "section_title": "referencing-values-with-refs", "url": "https://github.com/reactjs/react.dev/blob/main/src/content/learn/referencing-values-with-refs.md", "topics": "react,hooks,referencing,values,with,refs", "categories": "web,typescript,frontend,spa"}');
